import { MARGIN_TOP_STROKE, TRACK_HEIGHT } from '../constants.js';

/**
 * Checks whether mouse is in marker bounds
 *
 * @param mousePosition -
 * @param trackIndex -
 * @param markerCoords -
 */
export const inMarkerBounds = (
  mousePosition: { x: number; y: number },
  trackIndex: number,
  markerCoords: [number, number],
) => {
  const [start, end] = markerCoords;

  const top = trackIndex * TRACK_HEIGHT + MARGIN_TOP_STROKE;
  const bottom = (trackIndex + 1) * TRACK_HEIGHT + MARGIN_TOP_STROKE;

  return (
    mousePosition.y >= top &&
    mousePosition.y <= bottom &&
    mousePosition.x >= start &&
    mousePosition.x <= end
  );
};
